public Week(Date time, TimeZone zone) {
  if (time == null || zone == null) return;
  Calendar cal = Calendar.getInstance(zone, Locale.getDefault());
  cal.setTime(time);
  cal.set(Calendar.MILLISECOND, 0);
  int dayOfWeek = cal.get(Calendar.DAY_OF_WEEK);
  this.year = (short) cal.get(Calendar.YEAR);
  this.week = (byte) cal.get(Calendar.WEEK_OF_YEAR);
  this.firstMillisecond = cal.getTimeInMillis() - (dayOfWeek - 1) * 24 * 60 * 60 * 1000;
  this.lastMillisecond = this.firstMillisecond + 7 * 24 * 60 * 60 * 1000;
}
